// One-off: fix wrong logger import path that was generated by migrate-to-pino.mjs.
// The first version of the migration script wrote './utils/logger' for every file.
// This rewrites those to '../utils/logger' (except src/index.ts, which is correct).
import { readFileSync, writeFileSync, readdirSync, statSync } from 'fs';
import { join } from 'path';

const ROOT = process.cwd();
let fixed = 0;
let scanned = 0;

function walk(dir) {
  for (const entry of readdirSync(dir)) {
    const full = join(dir, entry);
    const s = statSync(full);
    if (s.isDirectory()) { walk(full); continue; }
    if (!full.endsWith('.ts')) continue;
    scanned++;
    const original = readFileSync(full, 'utf8');
    if (!original.includes("from './utils/logger'")) continue;
    const next = original.replace(/from '\.\/utils\/logger'/g, "from '../utils/logger'");
    writeFileSync(full, next);
    console.log('fixed:', full.replace(ROOT + '\\', ''));
    fixed++;
  }
}

walk(join(ROOT, 'src'));
console.log(`\nFix pass: ${fixed}/${scanned} file(s) updated.`);
